import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class XPathToSelector {
    public static void main(String[] args) {
        String xpath = "//input[@type='text']";
        String selector = "input[type='text']";
        convertXPathToSelector(xpath, selector);
        System.out.println("XPath: " + xpath);
        System.out.println("Selector: " + selector);
    }

    private static void convertXPathToSelector(String xpath, String selector) {
        // 使用正则表达式匹配 XPath 字符串
        Pattern pattern = Pattern.compile("([a-zA-Z]\\w*)");
        Matcher matcher = pattern.matcher(xpath);

        // 遍历 XPath 字符串中的每个组合别名
        while (matcher.find()) {
            String group = matcher.group();
            String[] parts = group.split(":");

            // 将别名转换为预期的 UI 选择器
            StringBuilder selectorBuilder = new StringBuilder();
            for (int i = 0; i < parts.length; i++) {
                selectorBuilder.append(parts[i]).append("[]");
                if (i < parts.length - 1) {
                    selectorBuilder.append("|");
                }
            }
            selector = selectorBuilder.toString();
        }

        System.out.println("XPath: " + xpath);
        System.out.println("Selector: " + selector);
    }
}
```
