    public static String convertXPathToSelector(String xpath) {
        String regex = "([a-zA-Z]\\w*)(\\s+[a-zA-Z0-9-_:.]+)*";
        String pattern = "\\s*(\\w+)\\s*=\\s*(\\w+)\\s*";
        String[] parts = xpath.split("/");
        StringBuilder selector = new StringBuilder();
        for (int i = 0; i < parts.length; i++) {
            String part = parts[i];
            if (part.contains("@")) {
                String attribute = part.split("\\@")[0];
                String value = part.split("\\@")[1];
                selector.append(attribute).append("=").append(value);
